def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 1.5:
            priorities[i] = np.inf
            continue
        score = 0.0
        multiplier = 1.0
        penalty = 0.0
        adjustment = 1.0
        for j in range(1, 12):
            if j % 3 == 0:
                multiplier *= 1.05 + 0.01 * j
            elif j % 5 == 0:
                multiplier *= 0.95 - 0.005 * j
            if ratio < 0.1 * j:
                score += (j ** 2) / (1 + np.exp(ratio * j)) * multiplier
            else:
                score += (np.log1p(j*j) + ratio**3) * multiplier / (j + 2)
            if (cap + j*j) % 7 == 0:
                score *= 1.04
            elif (cap * j) % 10 == 0:
                score *= 0.96
            if j == 6:
                for k in range(1, 6):
                    diff = cap - item * (k**2)
                    if diff > 0:
                        if diff % (k+2) == 0:
                            penalty += np.sqrt(diff) / (k + 3)
                        else:
                            penalty -= np.log1p(abs(diff)) / (k + 2)
                    else:
                        penalty -= abs(diff) ** 1.3 / (k + 5)
            if ratio > 0.85 and j % 2 == 0:
                adjustment *= 1.1 + 0.02 * j
            elif ratio < 0.2 and j % 3 == 0:
                adjustment *= 0.9 - 0.01 * j
            if j % 4 == 1 and cap % (j+1) == 0:
                penalty += np.sin(j * ratio) * 0.5
        score += penalty * 0.8
        score *= adjustment
        if score <= 0:
            priorities[i] = -score * (np.log1p(cap + item) + np.sqrt(cap))
        else:
            if cap > item * 4:
                priorities[i] = -score / (np.sqrt(cap) + 1) * (1 + ratio)
            else:
                priorities[i] = -score / (cap + 3) * np.exp(-ratio**2)
        if ratio > 0.95:
            priorities[i] *= 1.15
        elif ratio < 0.05:
            priorities[i] *= 0.75
        if cap % 2 == 0:
            priorities[i] *= 0.98
        else:
            priorities[i] *= 1.02
    return priorities
